package com.trademaster.ims.mobile.checkout.config;import com.trademaster.ims.mobile.checkout.model.DeliveryMethod;import com.trademaster.ims.mobile.checkout.repository.DeliveryMethodRepository;import org.springframework.boot.ApplicationArguments;import org.springframework.boot.ApplicationRunner;import org.springframework.stereotype.Component;import java.math.BigDecimal;
@Component public class DeliveryMethodInitializer implements ApplicationRunner{private final DeliveryMethodRepository r;public DeliveryMethodInitializer(DeliveryMethodRepository r){this.r=r;}public void run(ApplicationArguments a){seed("STANDARD_DELIVERY","Standard Delivery","Standard nationwide delivery",new BigDecimal("80.00"),3,5);seed("EXPRESS_DELIVERY","Express Delivery","Faster nationwide delivery",new BigDecimal("150.00"),1,2);}private void seed(String c,String n,String d,BigDecimal charge,int min,int max){if(r.existsByCode(c))return;DeliveryMethod m=new DeliveryMethod();m.setCode(c);m.setName(n);m.setDescription(d);m.setCharge(charge);m.setMinDays(min);m.setMaxDays(max);r.save(m);}}
